import React from 'react'

const Taskcard = ({ task }) => {
    return (
        <>
            <div className='task-card'>
                {task.title}
            </div>
            <Stylesheet/>
        </>
    )
}

const Stylesheet=()=>{
    return <style>{`
        .task-card{
            border:2px solid var(--text);
            min-width:250px;
            min-height:50px;
            border-radius: 5px;
            background-color:var(--secondary-color);
        }

